INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES (302, 11, "", "", 13020015, "", "", "いかんいかん\n資材の山に埋もれて\nしまうところだった", 111031, 10, "");
INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES (302, 91, "", "", 13020016, "", "", "", 0, "", "");
